const BASE_URL = "http://localhost:8000";

// ---------------- PING ----------------
export const ping = async () => {
  const res = await fetch(`${BASE_URL}/`);
  return res.json();
};

// ---------------- TRAIN ----------------
export const trainModel = async (data) => {
  const res = await fetch(`${BASE_URL}/train`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(data),
  });

  if (!res.ok) throw new Error("Train failed");
  return res.json();
};

// ---------------- PREDICT ----------------
export const predict = async (data) => {
  const res = await fetch(`${BASE_URL}/predict`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(data),
  });

  if (!res.ok) {
    const err = await res.json();
    throw new Error(err.detail || "Predict failed");
  }

  return res.json();
};

// ---------------- HISTORY ----------------
export const getHistory = async () => {
  const res = await fetch(`${BASE_URL}/history`);
  return res.json();
};

// ---------------- AUTOTUNE ----------------
export const autoTune = async (data) => {
  const res = await fetch(`${BASE_URL}/autotune`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(data),
  });

  return res.json();
};

// ---------------- UPLOAD DATASET ----------------
export const uploadDataset = async (file) => {
  const formData = new FormData();
  formData.append("file", file);

  const res = await fetch(`${BASE_URL}/upload`, {
    method: "POST",
    body: formData,
  });

  if (!res.ok) throw new Error("Upload failed");
  return res.json();
};

// ---------------- DOWNLOAD MODEL ----------------
export const downloadModel = async (modelId) => {
  const res = await fetch(`${BASE_URL}/download/${modelId}`);
  return res.blob();
};
